'use client'
import { cn, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useRef, type ChangeEvent, type KeyboardEvent } from 'react'
import styles from './search.module.css'

let idCounter = 0

export interface SearchProps {
  value?: string
  defaultValue?: string
  onChange?: (value: string) => void
  onSearch?: (value: string) => void
  debounceMs?: number
  placeholder?: string
  size?: 'sm' | 'md' | 'lg'
  label?: string
  disabled?: boolean
  clearLabel?: string
  id?: string
  className?: string
}

function MagnifierIcon() {
  return (
    <svg
      viewBox="0 0 16 16"
      width="16"
      height="16"
      fill="none"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="round"
      aria-hidden="true"
    >
      <circle cx="7" cy="7" r="4.5" />
      <line x1="10.5" y1="10.5" x2="14" y2="14" />
    </svg>
  )
}

export function Search({
  value,
  defaultValue = '',
  onChange,
  onSearch,
  debounceMs = 300,
  placeholder,
  size = 'md',
  label,
  disabled = false,
  clearLabel,
  id,
  className,
}: SearchProps) {
  useSignals()
  const resolvedPlaceholder = placeholder ?? t(builtin.search.placeholder)
  const resolvedLabel = label ?? t(builtin.search.label)
  const resolvedClearLabel = clearLabel ?? t(builtin.search.clear)
  const inputRef = useRef<HTMLInputElement>(null)

  const generatedIdRef = useRef('')
  if (generatedIdRef.current === '') {
    idCounter += 1
    generatedIdRef.current = `cascade-search-${idCounter}`
  }
  const inputId = id ?? generatedIdRef.current

  const isControlled = value !== undefined
  const current = useSignal(isControlled ? value : defaultValue)
  if (isControlled) current.value = value

  const onSearchRef = useRef(onSearch)
  onSearchRef.current = onSearch

  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const clearTimer = () => {
    if (timerRef.current !== null) {
      clearTimeout(timerRef.current)
      timerRef.current = null
    }
  }

  // Cancel any pending debounced search on unmount.
  useSignalEffect(() => clearTimer)

  const handleChange = (event: ChangeEvent<HTMLInputElement>) => {
    const next = event.target.value
    if (!isControlled) current.value = next
    onChange?.(next)
    clearTimer()
    timerRef.current = setTimeout(() => {
      timerRef.current = null
      onSearchRef.current?.(next)
    }, debounceMs)
  }

  const handleKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      clearTimer()
      onSearch?.(current.value)
    }
  }

  const handleClear = () => {
    clearTimer()
    if (!isControlled) current.value = ''
    onChange?.('')
    onSearch?.('')
    inputRef.current?.focus()
  }

  const filled = current.value !== ''

  return (
    <div
      className={cn(styles['root'], className)}
      data-size={size}
      data-state={filled ? 'filled' : 'empty'}
    >
      <label className={styles['label']} htmlFor={inputId}>
        {resolvedLabel}
      </label>
      <span className={styles['icon']}>
        <MagnifierIcon />
      </span>
      <input
        ref={inputRef}
        id={inputId}
        type="search"
        className={styles['input']}
        value={current.value}
        placeholder={resolvedPlaceholder}
        disabled={disabled}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
      />
      {filled && (
        <button
          type="button"
          className={styles['clear']}
          aria-label={resolvedClearLabel}
          disabled={disabled}
          onClick={handleClear}
        >
          <span aria-hidden="true">✕</span>
        </button>
      )}
    </div>
  )
}

@layer cascivo.component {
  .root {
    position: relative;
    display: inline-flex;
    align-items: center;
    inline-size: 100%;

    &[data-size='sm'] {
      --_search-height: 2rem;
      --_search-font: var(--cascivo-text-sm);
      --_search-px: var(--cascivo-space-3);
    }

    &[data-size='md'] {
      --_search-height: 2.5rem;
      --_search-font: var(--cascivo-text-sm);
      --_search-px: var(--cascivo-space-4);
    }

    &[data-size='lg'] {
      --_search-height: 3rem;
      --_search-font: var(--cascivo-text-base);
      --_search-px: var(--cascivo-space-4);
    }
  }

  /* Visually hidden but available to assistive technology. */
  .label {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    margin: -1px;
    padding: 0;
    border: 0;
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    overflow: hidden;
    white-space: nowrap;
  }

  .icon {
    position: absolute;
    inset-inline-start: var(--_search-px, var(--cascivo-space-4));
    display: inline-flex;
    align-items: center;
    color: var(--cascivo-color-text-muted);
    pointer-events: none;
  }

  .input {
    inline-size: 100%;
    block-size: var(--_search-height, 2.5rem);
    padding-inline-start: calc(
      var(--_search-px, var(--cascivo-space-4)) + 1rem + var(--cascivo-space-2)
    );
    padding-inline-end: calc(var(--_search-px, var(--cascivo-space-4)) + 1.5rem);
    font-family: var(--cascivo-font-sans);
    font-size: var(--_search-font, var(--cascivo-text-sm));
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);
    outline: none;

    /* Suppress the native WebKit search affordances; we render our own. */
    &::-webkit-search-cancel-button,
    &::-webkit-search-decoration {
      display: none;
      appearance: none;
      -webkit-appearance: none;
    }

    &::placeholder {
      color: var(--cascivo-color-text-muted);
    }

    &:hover:not(:disabled):not(:focus) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus {
      border-color: var(--cascivo-color-accent);
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      background-color: var(--cascivo-color-bg-subtle);
    }
  }

  .clear {
    position: absolute;
    inset-inline-end: var(--cascivo-space-2);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    padding: 0;
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-none);
    color: var(--cascivo-color-text-muted);
    background-color: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not(:disabled) {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      cursor: not-allowed;
    }
  }
}
